const express = require('express');
const app = express();
const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');

// Connect to MongoDB
mongoose.connect('mongodb://localhost/gameDB', { useNewUrlParser: true, useUnifiedTopology: true });

// Define user model
const User = new mongoose.Schema({
  username: String,
  password: String,
  rewards: Array
});

// Define level completion data model
const LevelCompletionData = new mongoose.Schema({
  userId: String,
  levelId: Number,
  score: Number,
  time: Number
});

// Mongoose models
const UserModel = mongoose.model('User', User);
const LevelCompletionDataModel = mongoose.model('LevelCompletionData', LevelCompletionData);

// Secret key for JWT token generation
const secretKey = 'your_secret_key_here';

// Middleware to validate user input and generate JWT tokens
app.use(express.json());

function validateInput(req, res, next) {
  if (!req.body.userId || !req.body.levelId || !req.body.score || !req.body.time) {
    return res.status(400).send({ message: 'Invalid request' });
  }
  next();
}

// Endpoint to complete a level
app.post('/complete-level', validateInput, async (req, res) => {
  try {
    const userId = req.body.userId;
    const levelId = req.body.levelId;
    const score = req.body.score;
    const time = req.body.time;

    // Validate user input using least privilege principle
    if (!await UserModel.exists({ _id: userId })) {
      return res.status(404).send({ message: 'User not found' });
    }

    // Generate JWT token for the user
    const token = jwt.sign({ userId }, secretKey, { expiresIn: '1h' });

    // Save level completion data to database
    await LevelCompletionDataModel.create({
      userId,
      levelId,
      score,
      time
    });

    // Award rewards based on client-reported metrics
    if (score > 1000 && time < 60) {
      await UserModel.updateOne({ _id: userId }, { $push: { rewards: 'Reward 1' } });
    }

    res.send({ message: 'Level completed successfully', token });
  } catch (error) {
    console.error(error);
    res.status(500).send({ message: 'Internal Server Error' });
  }
});

// Endpoint to claim rewards
app.post('/claim-rewards', validateInput, async (req, res) => {
  try {
    const userId = req.body.userId;

    // Validate user input using least privilege principle
    if (!await UserModel.exists({ _id: userId })) {
      return res.status(404).send({ message: 'User not found' });
    }

    // Generate JWT token for the user
    const token = jwt.sign({ userId }, secretKey, { expiresIn: '1h' });

    // Award rewards based on client-reported metrics
    await UserModel.updateOne({ _id: userId }, { $push: { rewards: 'Reward 2' } });

    res.send({ message: 'Rewards claimed successfully', token });
  } catch (error) {
    console.error(error);
    res.status(500).send({ message: 'Internal Server Error' });
  }
});

// Start server
const port = 3000;
app.listen(port, () => {
  console.log(`Server started on port ${port}`);
});